package com.socialblog.interaction.application;import com.fasterxml.jackson.databind.*;import com.socialblog.interaction.domain.*;import com.socialblog.interaction.repository.*;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.kafka.annotation.KafkaListener;import org.springframework.stereotype.Component;import org.springframework.transaction.annotation.Transactional;import java.util.UUID;@Component @ConditionalOnProperty(name="app.kafka.consumer-enabled",havingValue="true",matchIfMissing=true)public class TargetEventConsumer{private final ObjectMapper json;private final TargetProjectionRepository targets;private final ProcessedEventRepository processed;public TargetEventConsumer(ObjectMapper j,TargetProjectionRepository t,ProcessedEventRepository p){json=j;targets=t;processed=p;}@KafkaListener(topics={"articles.events","comments.events"})@Transactional public void consume(String raw)throws Exception{JsonNode e=json.readTree(raw);UUID event=UUID.fromString(e.path("eventId").asText());if(processed.existsById(event))return;String type=e.path("eventType").asText();TargetType targetType;String field;if(type.startsWith("Article")){targetType=TargetType.ARTICLE;field="articleId";}else if(type.startsWith("Comment")){targetType=TargetType.COMMENT;field="commentId";}else return;JsonNode payload=e.path("payload");UUID id=UUID.fromString(payload.path(field).asText());UUID owner=payload.hasNonNull("authorId")?UUID.fromString(payload.path("authorId").asText()):null;boolean active=type.endsWith("Published")||type.endsWith("Created");TargetKey key=new TargetKey(targetType,id);TargetProjection target=targets.findById(key).orElseGet(()->new TargetProjection(key,false,owner));target.update(active,owner);targets.save(target);processed.save(new ProcessedEvent(event,type));}}
